# C++ Program: Dictionary using a Binary Search Tree

This program implements a dictionary using a Binary Search Tree (BST), allowing users to add, search, and delete words and their definitions.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <iomanip>
#include <sstream>
#include <algorithm>

using namespace std;

// Node structure
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(const string& word, const string& definition) : word(word), definition(definition), left(nullptr), right(nullptr) {}
};

// BST operations
class BinarySearchTree {
private:
    Node* root;

    // Helper function to insert a node
    Node* insert(Node* node, const string& word, const string& definition);

    // Helper function to find a node
    Node* find(Node* node, const string& word);

    // Helper function to delete a node
    Node* deleteNode(Node* node, const string& word);

    // Helper function to print the tree
    void printTree(Node* node, int depth = 0);

public:
    BinarySearchTree() : root(nullptr) {}

    // Insert a word and its definition into the BST
    void insert(const string& word, const string& definition) {
        root = insert(root, word, definition);
    }

    // Find a word in the BST
    bool find(const string& word) {
        Node* node = find(root, word);
        return node != nullptr;
    }

    // Delete a word from the BST
    void deleteWord(const string& word) {
        root = deleteNode(root, word);
    }

    // Print the entire dictionary
    void printDictionary() {
        if (root == nullptr) {
            cout << "Dictionary is empty.\n";
            return;
        }

        cout << "Dictionary Entries:\n";
        printTree(root);
    }

    // Helper functions
    Node* insert(Node* node, const string& word, const string& definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->left = insert(node->left, word, definition);
        } else if (word > node->word) {
            node->right = insert(node->right, word, definition);
        }

        return node;
    }

    Node* find(Node* node, const string& word) {
        if (node == nullptr) {
            return nullptr;
        }

        if (word == node->word) {
            return node;
        }

        if (word < node->word) {
            return find(node->left, word);
        } else {
            return find(node->right, word);
        }
    }

    Node* deleteNode(Node* node, const string& word) {
        if (node == nullptr) {
            return node;
        }

        if (word < node->word) {
            node->left = deleteNode(node->left, word);
        } else if (word > node->word) {
            node->right = deleteNode(node->right, word);
        } else {
            // Node found, delete it
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                node = temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                node = temp;
            } else {
                Node* temp = node->right;
                while (temp->left != nullptr) {
                    temp = temp->left;
                }

                node->word = temp->word;
                node->definition = temp->definition;

                node->right = deleteNode(node->right, temp->word);
            }
        }

        return node;
    }

    void printTree(Node* node, int depth = 0) {
        if (node != nullptr) {
            printTree(node->right, depth + 1);
            cout << setw(20) << left << node->word << " : " << node->definition << "\n";
            printTree(node->left, depth + 1);
        }
    }
};

int main() {
    BinarySearchTree dict;

    string word, definition;
    int choice;

    while (true) {
        cout << "\nDictionary Menu:\n";
        cout << "1. Add Word and Definition\n";
        cout << "2. Search Word\n";
        cout << "3. Delete Word\n";
        cout << "4. Print Dictionary\n";
        cout << "5. Exit\n";
        cout << "Enter your choice: ";
        cin >> choice;

        if (choice == 5) {
            break;
        }

        if (choice == 1) {
            cout << "Enter word: ";
            cin >> word;
            cout << "Enter definition: ";
            cin >> definition;
            dict.insert(word, definition);
        } else if (choice == 2) {
            cout << "Enter word to search: ";
            cin >> word;
            if (dict.find(word)) {
                cout << "Definition found: " << word << " : " << dict.word << "\n";
            } else {
                cout << "Word not found.\n";
            }
        } else if (choice == 3) {
            cout << "Enter word to delete: ";
            cin >> word;
            dict.deleteWord(word);
            cout << "Word " << word << " deleted.\n";
        } else if (choice == 4) {
            dict.printDictionary();
        }
    }

    return 0;
}
```

---

### Features Implemented:

- **Insertion**: Words and their definitions are added to the BST.
- **Search**: Users can look up words in the dictionary.
- **Deletion**: Users can delete a word and its definition.
- **Printing**: The dictionary is printed in a clear and formatted manner.

### Notes:
- The program uses a simple `Node` class to represent each entry in the BST.
- The `BinarySearchTree` class manages the tree structure.
- The `printTree` function ensures the dictionary is displayed in a readable format with appropriate indentation for clarity.

This implementation is well-suited for a dictionary application with basic operations and is easy to extend with additional features like sorting or searching by definition.

